using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void Setup()
    {
        TestHelpers.DrainNotificationQueue();
        _sut = new NotificationService();
    }

    [TestCleanup]
    public void Cleanup()
    {
        while (_sut.ReceiveNotification() != null) { }
        _sut?.Dispose();
    }

    [TestMethod]
    public void SendNotification_EnqueuesNotification()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("TestUser", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_IncludesNameInMessage()
    {
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "TestUser");

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("John Doe"),
            $"Expected message to contain 'John Doe', got: {notification.Message}");
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_IncludesIdInMessage()
    {
        _sut.SendNotification("Student", "42", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("42"),
            $"Expected message to contain '42', got: {notification.Message}");
    }

    [TestMethod]
    public void SendNotification_NullDisplayName_IncludesIdInMessage()
    {
        _sut.SendNotification("Course", "99", (string)null, EntityOperation.UPDATE);

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("99"));
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        var result = _sut.ReceiveNotification();
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_DequeuesInOrder()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
        _sut.SendNotification("Student", "2", EntityOperation.UPDATE);
        _sut.SendNotification("Student", "3", EntityOperation.DELETE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();
        var third = _sut.ReceiveNotification();

        Assert.AreEqual("1", first.EntityId);
        Assert.AreEqual("2", second.EntityId);
        Assert.AreEqual("3", third.EntityId);
    }

    [TestMethod]
    public void ReceiveNotification_RemovesFromQueue()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();

        Assert.IsNotNull(first);
        Assert.IsNull(second);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op, verify it doesn't throw
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(0);
        _sut.MarkAsRead(-1);
        _sut.MarkAsRead(int.MaxValue);
    }

    [TestMethod]
    public void SendNotification_CREATE_GeneratesCreatedMessage()
    {
        _sut.SendNotification("Course", "101", "Math", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("created"),
            $"CREATE message should contain 'created', got: {notification.Message}");
        Assert.IsTrue(notification.Message.Contains("Math"));
    }

    [TestMethod]
    public void SendNotification_UPDATE_GeneratesUpdatedMessage()
    {
        _sut.SendNotification("Course", "101", "Math", EntityOperation.UPDATE);

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("updated"),
            $"UPDATE message should contain 'updated', got: {notification.Message}");
    }

    [TestMethod]
    public void SendNotification_DELETE_GeneratesDeletedMessage()
    {
        _sut.SendNotification("Course", "101", "Math", EntityOperation.DELETE);

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("deleted"),
            $"DELETE message should contain 'deleted', got: {notification.Message}");
    }

    [TestMethod]
    public void SendNotification_DefaultUserName_IsSystem()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();

        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAt()
    {
        var before = DateTime.Now;
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
        var after = DateTime.Now;

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
            $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
    }

    [TestMethod]
    public void SendNotification_SetsIsReadFalse()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();

        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        _sut.Dispose();
        _sut.Dispose(); // Double dispose should also be safe
    }

    [TestMethod]
    public void SendNotification_OverloadWithoutDisplayName_Works()
    {
        _sut.SendNotification("Department", "5", EntityOperation.UPDATE, "Admin");

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("Department", notification.EntityType);
        Assert.AreEqual("5", notification.EntityId);
        Assert.AreEqual("UPDATE", notification.Operation);
    }
}

