+        var dept = SeedDepartmentWithInstructor(context);
+
+        var course1 = new Course { CourseID = 2001, Title = "Math 101", Credits = 3, DepartmentID = dept.DepartmentID, Enrollments = new List<Enrollment>() };
+        var course2 = new Course { CourseID = 2002, Title = "Physics 101", Credits = 4, DepartmentID = dept.DepartmentID, Enrollments = new List<Enrollment>() };
+        context.Courses.AddRange(course1, course2);
+        context.SaveChanges();
+
+        var instructor = new Instructor
+        {
+            FirstMidName = "Jane",
+            LastName = "Smith",
+            HireDate = DateTime.Parse("2015-08-01"),
+            CourseAssignments = new List<CourseAssignment>()
+        };
+        context.Instructors.Add(instructor);
+        context.SaveChanges();
+
+        context.CourseAssignments.AddRange(
+            new CourseAssignment { InstructorID = instructor.ID, CourseID = course1.CourseID },
+            new CourseAssignment { InstructorID = instructor.ID, CourseID = course2.CourseID }
+        );
+        context.SaveChanges();
+
+        instructor.OfficeAssignment = new OfficeAssignment
+        {
+            InstructorID = instructor.ID,
+            Location = "Room 101"
+        };
+        context.SaveChanges();
+
+        return instructor;
+    }
+}
