+using Microsoft.VisualStudio.TestTools.UnitTesting;
+
+namespace ContosoUniversity.Tests;
+
+[TestClass]
+public sealed class PaginatedListTests
+{
+    [TestMethod]
+    public void Constructor_SetsPageIndexAndTotalPages()
+    {
+        // Arrange
+        var items = new List<int> { 1, 2, 3 };
+
+        // Act
+        var list = new PaginatedList<int>(items, 10, 2, 3);
+
+        // Assert
+        Assert.AreEqual(2, list.PageIndex);
+        Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
+        Assert.AreEqual(3, list.Count);
+    }
+
+    [TestMethod]
+    public void Constructor_AddsItemsToList()
+    {
+        // Arrange
+        var items = new List<string> { "a", "b", "c" };
+
+        // Act
+        var list = new PaginatedList<string>(items, 3, 1, 3);
+
+        // Assert
+        CollectionAssert.AreEqual(new[] { "a", "b", "c" }, list.ToList());
+    }
+
+    [TestMethod]
+    public void HasPreviousPage_FirstPage_ReturnsFalse()
+    {
+        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
+        Assert.IsFalse(list.HasPreviousPage);
+    }
+
+    [TestMethod]
+    public void HasPreviousPage_SecondPage_ReturnsTrue()
+    {
+        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
+        Assert.IsTrue(list.HasPreviousPage);
+    }
+
+    [TestMethod]
+    public void HasNextPage_LastPage_ReturnsFalse()
+    {
+        // TotalPages = ceil(10/5) = 2, PageIndex = 2
+        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
+        Assert.IsFalse(list.HasNextPage);
+    }
+
+    [TestMethod]
+    public void HasNextPage_NotLastPage_ReturnsTrue()
+    {
+        // TotalPages = ceil(10/5) = 2, PageIndex = 1
+        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
+        Assert.IsTrue(list.HasNextPage);
+    }
+
+    [TestMethod]
+    public void Create_ReturnsCorrectPage()
+    {
+        // Arrange
+        var source = Enumerable.Range(1, 20).AsQueryable();
+
+        // Act
+        var result = PaginatedList<int>.Create(source, 2, 5);
+
+        // Assert
+        Assert.AreEqual(2, result.PageIndex);
+        Assert.AreEqual(4, result.TotalPages);
+        Assert.AreEqual(5, result.Count);
+        Assert.AreEqual(6, result[0]); // Second page starts at item 6
+    }
+
+    [TestMethod]
+    public void Create_FirstPage_ReturnsFirstItems()
+    {
+        var source = Enumerable.Range(1, 10).AsQueryable();
+
+        var result = PaginatedList<int>.Create(source, 1, 3);
+
+        Assert.AreEqual(1, result.PageIndex);
+        Assert.AreEqual(4, result.TotalPages);
+        CollectionAssert.AreEqual(new[] { 1, 2, 3 }, result.ToList());
+    }
+
+    [TestMethod]
+    public void Create_LastPage_ReturnsRemainingItems()
+    {
+        var source = Enumerable.Range(1, 7).AsQueryable();
+
+        var result = PaginatedList<int>.Create(source, 3, 3);
+
+        Assert.AreEqual(3, result.PageIndex);
+        Assert.AreEqual(3, result.TotalPages);
+        CollectionAssert.AreEqual(new[] { 7 }, result.ToList());
+    }
+
+    [TestMethod]
+    public void Create_EmptySource_ReturnsEmptyList()
+    {
+        var source = Enumerable.Empty<int>().AsQueryable();
+
+        var result = PaginatedList<int>.Create(source, 1, 5);
+
+        Assert.AreEqual(0, result.Count);
+        Assert.AreEqual(0, result.TotalPages);
+        Assert.IsFalse(result.HasPreviousPage);
+        Assert.IsFalse(result.HasNextPage);
+    }
+
+    [TestMethod]
+    public void TotalPages_ExactDivision_CalculatedCorrectly()
+    {
+        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
+        Assert.AreEqual(2, list.TotalPages);
+    }
+
+    [TestMethod]
+    public void TotalPages_WithRemainder_RoundsUp()
+    {
+        var list = new PaginatedList<int>(new List<int>(), 11, 1, 5);
+        Assert.AreEqual(3, list.TotalPages);
+    }
+
+    [TestMethod]
+    public void TotalPages_SingleItem_IsOne()
+    {
+        var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);
+        Assert.AreEqual(1, list.TotalPages);
+    }
+
+    [TestMethod]
+    [DataRow(1, false, true, DisplayName = "Page 1 of 3")]
+    [DataRow(2, true, true, DisplayName = "Page 2 of 3")]
+    [DataRow(3, true, false, DisplayName = "Page 3 of 3")]
+    public void Navigation_VariousPages_ReturnsCorrectFlags(int pageIndex, bool expectedPrev, bool expectedNext)
+    {
+        // 15 items, 5 per page = 3 pages
+        var list = new PaginatedList<int>(new List<int>(), 15, pageIndex, 5);
+
+        Assert.AreEqual(expectedPrev, list.HasPreviousPage);
+        Assert.AreEqual(expectedNext, list.HasNextPage);
+    }
+}
