    [TestMethod]
    [DataRow(".jpg", DisplayName = "JPG extension allowed")]
    [DataRow(".jpeg", DisplayName = "JPEG extension allowed")]
    [DataRow(".png", DisplayName = "PNG extension allowed")]
    [DataRow(".gif", DisplayName = "GIF extension allowed")]
    [DataRow(".bmp", DisplayName = "BMP extension allowed")]
    public void Create_POST_ValidImageExtension_DoesNotAddExtensionError(string extension)
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();
        var dept = TestHelpers.SeedDepartmentWithInstructor(context);
        var controller = CreateController(context);
        var course = new Course
        {
            CourseID = 3010 + extension.GetHashCode() % 1000,
            Title = "Course",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns($"test{extension}");
        mockFile.Setup(f => f.Length).Returns(1024); // 1KB, well under limit
        mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));

        // Act
        var result = controller.Create(course, mockFile.Object);

        // Assert - should not have extension-related model error
        var hasExtensionError = controller.ModelState.ContainsKey("teachingMaterialImage") &&
            controller.ModelState["teachingMaterialImage"].Errors.Any(e => e.ErrorMessage.Contains("valid image file"));
        Assert.IsFalse(hasExtensionError, $"Extension {extension} should be allowed");
    }

